package main

import (
	"sort"
)

func abs(x int64) int64 {
	if x < 0 {
		return -x
	}
	return x
}

func solve(nums []int64) int64 {
	n := len(nums)
	if n < 2 {
		return 0
	}

	sortedAbs := make([]int64, n)
	for i := 0; i < n; i++ {
		sortedAbs[i] = abs(nums[i])
	}

	sort.Slice(sortedAbs, func(i, j int) bool {
		return sortedAbs[i] < sortedAbs[j]
	})

	var total int64 = 0
	for i := 0; i < n-1; i++ {
		target := sortedAbs[i] * 2
		left := i + 1
		right := n - 1
		res := i

		for left <= right {
			mid := (left + right) / 2
			if sortedAbs[mid] <= target {
				res = mid
				left = mid + 1
			} else {
				right = mid - 1
			}
		}

		total += int64(res - i)
	}

	return total
}
